head.script:
scwin.lobranCd = "";
scwin.lobranNm = "";
scwin.empNo = "";
scwin.onpageload = function () {
    $c.gus.cfDisableObjects([udc_button, btn_DeleteAllRow, btn_save, btn_confirm]); // , btn_UndoRow
    let memJson = $c.data.getMemInfo();
    scwin.lobranCd = memJson.lobranCd;
    scwin.lobranNm = memJson.lobranNm;
    scwin.empNo = memJson.empNo;
    console.log("### onpageload :: " + JSON.stringify(memJson));
    scwin.getManager();
};

scwin.onUdcCompleted = function () {
    ed_clntNo.setValue("000001");
    ed_clntNm.setValue("보랄석고보드시스템");
    ed_srchWrkStDt.setValue(WebSquare.date.getCurrentServerDate("yyyyMMdd"));
    ed_srchWrkEndDt.setValue(WebSquare.date.getCurrentServerDate("yyyyMMdd"));
}

//조회조건 초기화
scwin.f_FieldClear = function () {
    // $c.gus.cfInitObjects([tb_mainData]);
    ed_srchWrkStDt.setValue(WebSquare.date.getCurrentServerDate("yyyyMMdd"));
    ed_srchWrkEndDt.setValue(WebSquare.date.getCurrentServerDate("yyyyMMdd"));
    ed_clntNo.setValue("000001");
    ed_clntNm.setValue("보랄석고보드시스템");

    ed_bizLongCd.setValue("");
    ed_bizLongNm.setValue("");
    lc_amtGb.setSelectedIndex(0);
    lc_confirmYn.setSelectedIndex(0);
    ed_odrNo.setValue("");
    ed_mchtOdrNo.setValue("");

    scwin.f_lobranCdControl();

    ed_clntNo.focus();
}

//-------------------------------------------------------------------------
// 공통코드 조회 (전산 담당자 조회 후 등록점소 셋팅)
//-------------------------------------------------------------------------
scwin.getManager = async function () {
    // 데이타셋 초기화 필요
    ds_manager.removeAll();

    //	var pCode = '<%=empNo%>' ;
    var pCode = scwin.empNo;

    // SELECT 절 
    var param1 = "CD_NM  as COL1 , CD  as COL2 , ''  as COL3 , ''  as COL4 , ''  as COL5 , ''  as COL6 , ''  as COL7 , ''  as COL8 , ''  as COL9 , ''  as COL10";

    // 대상테이블 	
    var param2 = " TB_ZZ002 ";

    // 조건절
    var param3 = "AND GRP_CD = 'BRL06' AND USE_YN='1' AND CD = '" + pCode + "' ";//크나우프전산담당자

    var param4 = "CD";

    //	ds_empNo.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
    //	ds_empNo.Reset();

    // FI624 (증빙관리권한) - 01: user01, 02: user31, 03: user32, 04: user33, 05: user34, 06: user35, 07: user36, 08: user37
    // 2025-10-02 : 세무조사시에만 사용하는 계정으로 , 세무조사 인원이 조회시 보이지 않아야 하는 부분으로 구현 필요

    const strParam = {
        sysCd: "CommonEBC"           // 시스템코드
        , queryId: "dinymicQueryTest"    // 쿼리ID
        , param1: param1                // SELECT
        , param2: param2                // 대상테이블
        , param3: param3                // 조건절
        , param4: param4                // CD
    };

    //데이터셋에 정보설정
    ds_commonCode.setJSON(strParam);
    await $c.sbm.execute(sbm_searchCommon);
};

scwin.sbm_searchCommon_submitdone = function (e) {
    if (e.responseJSON.GAUCE[0]) {
        ds_manager.insertRow();
        ds_manager.setRowJSON(0, e.responseJSON.GAUCE[0]);
    }
    scwin.f_lobranCdControl();
    scwin.f_bConfirmControl();
}

scwin.f_lobranCdControl = function () {
    if (ds_manager.getTotalRow() > 0) {
        ed_regBranCd.setValue("");
        ed_regBranNm.setValue("");
    } else {
        ed_regBranCd.setValue(scwin.lobranCd);
        ed_regBranNm.setValue(scwin.lobranNm);
        $c.gus.cfDisableObjects([ed_regBranCd, ed_regBranNm, btn_PopUp3]);
    }
}

scwin.f_bConfirmControl = function () {
    var confirmYn = lc_confirmYn.getValue();

    if (ds_manager.getTotalRow() > 0) {
        if (confirmYn == "0") {
            $c.gus.cfEnableObjects([btn_confirm]);
        } else {
            $c.gus.cfDisableObjects([btn_confirm]);
        }
    } else {
        $c.gus.cfDisableObjects([btn_confirm]);
    }
}

/* 확정처리 */
scwin.f_Confirm = async function () {
    if (lc_amtGb.getValue() == "") {
        $c.win.alert("예외운송 또는 휴일운송을 선택 후 미확정 내역을 조회하시길 바랍니다.");
        return;
    }
    // TODO ::
    if (ds_master.getTotalRow() != 0) {
        var cnt = ds_master.getTotalRow();
        var total = gr_master.getFooterData("fSellAmt");

        var msg = $c.gus.cfInsertComma(total) + "원에 대해 확정처리 하시겠습니까? (" + $c.gus.cfInsertComma(cnt) + "건)";
        var rtn = await $c.win.confirm(msg);
        if (rtn) {
            ds_Query.set("clntNo", ed_clntNo.getValue());
            ds_Query.set("bizLongCd", ed_bizLongCd.getValue());
            ds_Query.set("odrDtFrom", ed_srchWrkStDt.getValue());
            ds_Query.set("odrDtTo", ed_srchWrkEndDt.getValue());
            ds_Query.set("amtGb", lc_amtGb.getValue() == "all" ? "" : lc_amtGb.getValue());
            ds_Query.set("wrkPlCd", "");
            ds_Query.set("lobranCd", ed_regBranCd.getValue());
            ds_Query.set("confirmYn", lc_confirmYn.getValue() == "all" ? "" : lc_confirmYn.getValue());
            ds_Query.set("odrNo", ed_odrNo.getValue());
            ds_Query.set("mchtOdrNo", ed_mchtOdrNo.getValue());

            $c.sbm.execute($p, sbm_confirm);
        }
    } else {
        $c.gus.cfAlertMsg("확정처리할 데이터가 없습니다.");
        return;
    }

}

/* 저장 */
scwin.f_Save = async function () {
    // 필수입력사항 확인
    // 		if ( !cfValidate([gr_master])) {
    // 			return;
    // 		}
    // 변경된 사항이 있는지 확인.
    if (ds_master.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }
    var msg = "저장하시겠습니까?";
    let rtn = await $c.win.confirm(msg);
    if (rtn) {

        // 확정된 내역은 삭제할수없다.
        var confirmCnt = 0;
        for (var i = 0; i < ds_master.getTotalRow(); i++) {
            if (ds_master.getRowStatus(i) == "D") { // 삭제건에 한해서 확정유무 체크
                if (ds_master.getCellData(i, "confirmYn") == "1") {
                    confirmCnt++;
                }
            }
        }
        if (confirmCnt > 0) {
            $c.win.alert("확정된 건은 변경할 수 없습니다.");
            return;
        }
        var cnt = 0;
        ds_save.removeAll();
        for (var i = 0; i < ds_master.getTotalRow(); i++) {
            if (ds_master.getRowStatus(i) != "R") {
                ds_save.setRowJSON(cnt, ds_master.getRowJSON(i));
                if (ds_master.getRowStatus(i) == "D") ds_save.modifyRowStatus(cnt, "D");
                cnt++;
            }
        }
        $c.sbm.execute(sbm_save);
    }
}

/* 조회 */
scwin.f_Retrieve = async function () {
    // 거래처 선택 확인
    if ($c.gus.cfIsNull(ed_clntNo.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("거래처"));
        ed_clntNo.focus();
        return false;
    }

    if (ed_srchWrkStDt.getValue() == "") {
        await $c.win.alert("작업 조회 시작일자은(는) 필수 입력 항목입니다.");
        ed_srchWrkStDt.focus();
        return;
    }

    if (ed_srchWrkEndDt.getValue() == "") {
        await $c.win.alert("작업 조회 종료일자은(는) 필수 입력 항목입니다.");
        ed_srchWrkEndDt.focus();
        return;
    }

    if (!$c.gus.cfIsAfterDate(ed_srchWrkStDt.getValue(), ed_srchWrkEndDt.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_srchWrkStDt.focus();
        return;
    }

    ds_Query.set("clntNo", ed_clntNo.getValue());
    ds_Query.set("bizLongCd", ed_bizLongCd.getValue());
    ds_Query.set("odrDtFrom", ed_srchWrkStDt.getValue());
    ds_Query.set("odrDtTo", ed_srchWrkEndDt.getValue());
    ds_Query.set("amtGb", lc_amtGb.getValue() == "all" ? "" : lc_amtGb.getValue());
    ds_Query.set("wrkPlCd", "");
    ds_Query.set("lobranCd", ed_regBranCd.getValue());
    ds_Query.set("confirmYn", lc_confirmYn.getValue() == "all" ? "" : lc_confirmYn.getValue());
    ds_Query.set("odrNo", ed_odrNo.getValue());
    ds_Query.set("mchtOdrNo", ed_mchtOdrNo.getValue());

    $c.sbm.execute($p, sbm_retrieve);
}

scwin.sbm_retrieve_submitdone = function (e) {
    debugger;
    $c.gus.cfEnableObjects([udc_button, btn_DeleteAllRow, btn_save]); // , btn_UndoRow
    if (ds_master.getTotalRow() == 0) {
        $c.win.alert("조회된 데이터가 없습니다.");
        eb_total.setValue("0");
        return;
    }
    eb_total.setValue(ds_master.getTotalRow());
    ds_master.modifyAllStatus("R");
    for (var i = 0; i < ds_master.getTotalRow(); i++) {
        if (ds_master.getRowStatus(i) == "R") gr_master.setRowReadOnly(i, true);
    }
    gr_master.setFocusedCell(0, 0);
}

/* 초기화 */
scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

/* 확정 */
scwin.btn_confirm_onclick = function (e) {
    scwin.f_Confirm();
};

/* 저장 */
scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

/* 조회 */
scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

/* 그리드 팝업 */
scwin.textImage = false;
scwin.gr_master_ontextimageclick = function (rowIndex, columnIndex) {
    scwin.textImage = true;
    row = rowIndex;
    if (ds_master.getCellData(row, "amtGb").trim() == "") {
        $c.win.alert("구분값을 먼저 선택해주세요.");
        return;
    }
    if (ds_master.getRowStatus(rowIndex) != "R" && ds_master.getRowStatus(rowIndex) != "D") scwin.f_openGridPopup(rowIndex, columnIndex);
};

/* 전체삭제 */
scwin.btn_DeleteAllRow_onclick = function (e) {
    for (var i = ds_master.getTotalRow() - 1; i >= 0; i--) {
        if (ds_master.getRowStatus(i) == "C") {
            ds_master.removeRow(i);
        } else {
            ds_master.deleteRow(i);
        }
    }
};

scwin.f_openGridPopup = async function (row, columnIndex) {
    var odrNo = "";
    var mchtOdrNo = "";
    var clntNo = ed_clntNo.getValue();
    var wrkPlCd = hid_wrkPlCd.getValue();
    var lobranCd = ed_regBranCd.getValue();

    if (columnIndex == "1") { // 2 > 오더번호
        odrNo = ds_master.getCellData(row, "odrNo");
    } else if (columnIndex == "6") { // 8 > 크나우프 오더번호
        mchtOdrNo = ds_master.getCellData(row, "mchtOdrNo");
    }

    var data = {
        odrNo: odrNo
        , mchtOdrNo: mchtOdrNo
        , clntNo: clntNo
        , wrkPlCd: wrkPlCd
        , lobranCd: lobranCd
    };

    var opts = {
        id: "smpPop"
        , popupName: "크나우프 오더정보 조회"
        , modal: true
        , type: "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        , title: "Win pop"  //Layer pop
        , width: 1000
        , height: 550
    };
    rtn = await $c.win.openPopup("/ui/ds/op/wrkrslts/transwrkrslts/op_304_01_66p.xml", opts, data);
    scwin.orderNoPopup_callBackFunc(rtn);
}

scwin.orderNoPopup_callBackFunc = function (rtnList) {
    debugger;
    if (rtnList != null) {
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "odrNo", rtnList.odrNo);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "sellSeq", rtnList.sellSeq);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "mchtOdrNo", rtnList.mchtOdrNo);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "bizLongCd", rtnList.bizLongCd);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "bizLongNm", rtnList.bizLongNm);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "dmndNo", rtnList.dmndNo);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "salePlCoNm", rtnList.salePlCoNm);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "wrkPatternCd", rtnList.wrkPatternCd);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "commClssCd", rtnList.commClssCd);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "commClssNm", rtnList.commClssNm);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "clntCommCd", rtnList.clntCommCd);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "commNm", rtnList.commNm);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "wrkQty", rtnList.wrkQty);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "qtyUnitCd", rtnList.qtyUnitCd);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "smQty", rtnList.smQty);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "smQty1", rtnList.smQty1);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "wrkWt", rtnList.wrkWt);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "unitCd", rtnList.unitCd);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "arvWrkPlCd", rtnList.arvWrkPlCd);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "arvWrkPlCd1", rtnList.arvWrkPlCd1);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "arvWrkPlCd2", rtnList.arvWrkPlCd2);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "osideCdNm", rtnList.osideCdNm);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "tplZip", rtnList.tplZip);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "odrDt", rtnList.odrDt);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "ioDt", rtnList.ioDt);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "selfVehclNo", rtnList.selfVehclNo);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "maxShipwgtVol", rtnList.maxShipwgtVol);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "selpchItemNm", rtnList.selpchItemNm);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "dptWrkPlCd", rtnList.dptWrkPlCd);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "transWrkIndictNo", rtnList.transWrkIndictNo);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "commCd", rtnList.commCd);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "bizLongNm1", rtnList.bizLongNm);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "dmndNo1", rtnList.dmndNo);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "salePlCoNm1", rtnList.salePlCoNm);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "mchtOdrNo1", rtnList.mchtOdrNo);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "warehouseNm", rtnList.warehouseNm);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "warehouseNm1", rtnList.warehouseNm);

        ds_master.setCellData(gr_master.getFocusedRowIndex(), "dptDt", rtnList.dptDt);
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "regBranCd", rtnList.regBranCd);
        scwin.odrNo = rtnList.odrNo;
        scwin.odrNo2 = rtnList.mchtOdrNo;

        if (ds_master.getCellData(gr_master.getFocusedRowIndex(), "amtGb") == "2") {//휴일운송비일경우
            var sellAmt = +rtnList.sellAmt;	//매출금액
            var wrkWt = +rtnList.wrkWt;	//작업중량
            var sellUpr = +rtnList.sellUpr;	//매출단가
            var sellAmt150 = +rtnList.sellAmt;	//매출금액*1.5

            sellAmt150 = Math.round((+rtnList.sellUpr * 1.5 * wrkWt), 0);	//매출단가 * 1.5
            // 				sellAmt = Math.round((rtnList.sellUpr * 0.5 * wrkWt),0);	//매출단가 * 0.5

            ds_master.setCellData(gr_master.getFocusedRowIndex(), "sellAmt150", sellAmt150);
            ds_master.setCellData(gr_master.getFocusedRowIndex(), "sellAmt", sellAmt150 - sellAmt);
            gr_master.setCellReadOnly(gr_master.getFocusedRowIndex(), "sellAmt", true);
            // gr_master.ColumnProp("sellAmt", "Edit") = "None";
        } else {
            ds_master.setCellData(gr_master.getFocusedRowIndex(), "sellAmt150", "0");
            ds_master.setCellData(gr_master.getFocusedRowIndex(), "sellAmt", "0");
            // gr_master.ColumnProp("sellAmt", "Edit") = "ANY";
            gr_master.setCellReadOnly(gr_master.getFocusedRowIndex(), "sellAmt", false);
        }
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "confirmYn", "0");
    } else {
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "odrNo", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "sellSeq", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "mchtOdrNo", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "bizLongCd", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "bizLongNm", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "dmndNo", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "salePlCoNm", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "wrkPatternCd", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "commClssCd", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "commClssNm", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "clntCommCd", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "commNm", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "wrkQty", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "qtyUnitCd", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "smQty", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "smQty1", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "wrkWt", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "unitCd", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "arvWrkPlCd", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "arvWrkPlCd1", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "arvWrkPlCd2", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "osideCdNm", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "tplZip", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "odrDt", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "ioDt", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "selfVehclNo", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "maxShipwgtVol", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "selpchItemNm", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "dptWrkPlCd", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "transWrkIndictNo", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "commCd", "");

        ds_master.setCellData(gr_master.getFocusedRowIndex(), "bizLongNm1", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "dmndNo1", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "salePlCoNm1", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "mchtOdrNo1", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "warehouseNm", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "warehouseNm1", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "dptDt", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "sellAmt", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "sellAmt150", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "regBranCd", "");
        ds_master.setCellData(gr_master.getFocusedRowIndex(), "confirmYn", "0");
        scwin.odrNo = "";
        scwin.odrNo2 = "";
    }
}

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {

    switch (disGubun) {
        case 1: // 거래처 팝업
            udc_clntNo.setSelectId("retrieveClntInfo2"); // XML상의 SELECT ID
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "계약 거래처,거래처코드,거래처명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;
        case 2: // 사업장 팝업	
            var v_clntNo = ed_clntNo.getValue();
            var v_itemCd = "BIZ";	// 사업장 조회
            var v_wrkPlCd = "999";

            // 거래처 선택 확인
            if ($c.gus.cfIsNull(v_clntNo)) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("거래처"));
                ed_clntNo.focus();
                return;
            }

            pWhere = v_clntNo + "," + v_itemCd + "," + v_wrkPlCd;

            udc_bizLongCd.setSelectId("retrieveEdiMapping"); // XML상의 SELECT ID
            udc_bizLongCd.cfCommonPopUp(scwin.udc_bizLongCd_callBackFunc // 콜백 함수
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서	
                , null					// 보여주는 각 컬럼들의 폭	
                , null					// 컬럼중에서 숨기는	컬럼 지정	
                , pWhere					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "사업장,사업장코드,사업장명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;
        case 3: // 등록점소
            pWhere = ",,,T";    // 물류점소구분코드 : LO120 - 팀(T), 지점(A), 사업소(B), CY(C), CFS(F)
            udc_regBranCd.setSelectId("retrieveLogisDeptInfo"); // XML상의 SELECT ID
            udc_regBranCd.cfCommonPopUp(scwin.udc_regBranCd_callBackFunc // 콜백 함수
                , pCode                  // 화면에서의 ??? Code Element의  Value
                , pName                  // 화면에서의 ??? Name Element의  Value
                , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                , null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   // Title순서
                , null                   // 보여주는 각 컬럼들의 폭
                , null                   // 컬럼중에서 숨기는    컬럼 지정
                , pWhere                 // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                , null                   // POP-UP뛰을때 우도우의   사용자 정의  높이
                , null                   // 윈도우 위치 Y좌표
                , null                   // 윈도우 위치 X좌표
                , null                   // 중복체크여부   ("F")
                , pAllSearch                 // 전체검색허용여부 ("F")
                , "등록점소,점소코드,점소명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
    }
}

