scwin.delRow = function () {
    var row = gr_master.getFocusedRowIndex();
    if (ds_master.getRowStatus(row) == "R") {
        ds_master.modifyRowStatus(row, "D");
    } else {
        ds_master.removeRow(row);
    }
}

scwin.sbm_save_submitdone = function (e) {
    scwin.f_Retrieve();
}
scwin.gr_master_onafteredit = function (rowIndex, columnIndex, value) {
    scwin.textImage = false;
    setTimeout(function () {
        if (scwin.textImage) return;
        row = rowIndex;
        colid = gr_master.getColumnID(columnIndex);
        if (colid == "odrNo" && scwin.odrNo == value) return;
        if (colid == "mchtOdrNo" && scwin.odrNo2 == value) return;
        olddata = value;
        if (colid == "odrNo" || colid == "mchtOdrNo") {
            scwin.textImage = false;
            if (ds_master.getCellData(row, "amtGb").trim() == "") {
                $c.win.alert("구분값을 먼저 선택해주세요.");
                ds_master.setCellData(row, colid, "");
                return;
            }
            var odrNo = ds_master.getCellData(row, "odrNo");
            var mchtOdrNo = ds_master.getCellData(row, "mchtOdrNo");

            if ((colid == "odrNo" && odrNo != "") || (colid == "mchtOdrNo" && mchtOdrNo != "")) {
                if (colid == "odrNo") {
                    scwin.f_openGridPopup(row, "1");
                } else if (colid == "mchtOdrNo") {
                    scwin.f_openGridPopup(row, "6");
                }
            }
        }
    }, 100);
};

scwin.excel = async function () {
    filename = "크나우프예외/휴일운송비조회";
